#include<bits/stdc++.h>
using namespace std;
#define inf INT_MAX
#define int long long
const int maxn=1e4+5;
int t,n,m,ans;
struct node {
	vector<pair<int,int>>e;
	int d=inf,b,c;
} v[maxn];
queue<int>q;
void check(int id,int dis) {
	if(dis<v[id].d) {
		v[id].d=dis;
		if(v[id].b==0) {
			v[id].b=1,q.push(id);
			ans&=++v[id].c<n; 
		}
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	for(cin>>t; t--;) {
		cin>>n>>m;
		fill(v,v+1+n,v[0]),q=queue<int>(),ans=1;
		for(int i=1,x,y,z; i<=m; i++) {
			cin>>x>>y>>z,v[x].e.emplace_back(y,z);
			if(z>=0) v[y].e.emplace_back(x,z);
		}
		for(check(1,0); q.size()&&ans;) {
			int p=q.front();
			q.pop(),v[p].b=0;
			for(auto x:v[p].e) check(x.first,x.second+v[p].d);
		}
		if(ans){
			cout<<"NO";
		}else{
			cout<<"YES";
		}
		cout<<"\n";
	}
	return 0;
}
